pairs.fixed_source:
fn main() -> Void {
    if !has_toon() {
        fx {
            println("TOON unavailable");
        }
        ret;
    }

    let doc: ToonDoc = toon_parse("{\"items\":[{\"id\":1,\"meta\":{\"code\":\"A\"}},{\"id\":2}]}");
    let root: ToonNode = toon_root(doc);
    let items: ToonNode = toon_key(root, "items");

    loop i in 0..toon_len(items) {
        let item: ToonNode = toon_at(items, i);
        let id: Int = toon_get_int(item, "id");
        let code: Text = "UNKNOWN";

        if toon_has_key(item, "meta") {
            let meta: ToonNode = toon_key(item, "meta");
            code = toon_get_text_or(meta, "code", "MISSING");
        }

        fx {
            println("Item ", id, " has code: ", code);
        }
    }

    toon_close(doc);
    ret;
}

